import React, { useContext } from 'react';
import { Link } from 'react-router-dom';
import { FaComment, FaThumbsUp, FaBookmark, FaRegBookmark, FaUser } from 'react-icons/fa';
import { toast } from 'react-toastify';
import formatDate from '../utils/formatDate';
import AuthContext from '../context/AuthContext';
import forumService from '../services/forumService';

const ForumPostCard = ({ post, onActionComplete }) => {
  const { user } = useContext(AuthContext);
  
  const truncateText = (text, maxLength = 150) => {
    if (!text) return '';
    if (text.length <= maxLength) return text;
    return text.substring(0, maxLength) + '...';
  };
  
  const handleLike = async () => {
    try {
      if (!user) {
        toast.warning('You must be logged in to like posts');
        return;
      }
      
      await forumService.likePost(post._id);
      if (onActionComplete) onActionComplete();
    } catch (error) {
      toast.error('Failed to like post: ' + error.message);
    }
  };
  
  const handleBookmark = async () => {
    try {
      if (!user) {
        toast.warning('You must be logged in to bookmark posts');
        return;
      }
      
      await forumService.bookmarkPost(post._id);
      if (onActionComplete) onActionComplete();
    } catch (error) {
      toast.error('Failed to bookmark post: ' + error.message);
    }
  };

  return (
    <div className="bg-white rounded-lg shadow-md p-4 mb-4 border border-gray-200 hover:shadow-lg transition duration-300">
      <div className="flex justify-between items-start mb-3">
        <div className="flex items-center">
          <div className="bg-green-100 p-2 rounded-full mr-3">
            <FaUser className="text-green-600" />
          </div>
          <div>
            <p className="font-semibold">{post.author.name}</p>
            <p className="text-xs text-gray-500">{formatDate(post.createdAt, { withRelativeTime: true })}</p>
          </div>
        </div>
        <span className="text-xs px-2 py-1 bg-green-100 text-green-800 rounded-full">{post.category}</span>
      </div>
      
      <Link to={`/forum/${post._id}`} className="block hover:text-green-700">
        <h3 className="text-xl font-semibold mb-2">{post.title}</h3>
        <p className="text-gray-700 mb-4">{truncateText(post.content)}</p>
      </Link>
      
      {post.image && (
        <img 
          src={post.image} 
          alt={post.title} 
          className="w-full h-48 object-cover rounded-md mb-4"
        />
      )}
      
      <div className="flex items-center justify-between text-gray-600">
        <div className="flex space-x-4">
          <button 
            onClick={handleLike}
            className={`flex items-center space-x-1 ${post.likes?.includes(user?._id) ? 'text-green-600' : ''}`}
          >
            <FaThumbsUp />
            <span>{post.likes?.length || 0}</span>
          </button>
          
          <Link to={`/forum/${post._id}`} className="flex items-center space-x-1">
            <FaComment />
            <span>{post.comments?.length || 0}</span>
          </Link>
        </div>
        
        <button 
          onClick={handleBookmark}
          className={post.bookmarks?.includes(user?._id) ? 'text-green-600' : ''}
        >
          {post.bookmarks?.includes(user?._id) ? <FaBookmark /> : <FaRegBookmark />}
        </button>
      </div>
    </div>
  );
};

export default ForumPostCard;
